// frontend/src/pages/Register.jsx
import { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import apiClient from '../api/client';
import { GoogleLogin } from '@react-oauth/google';

export default function Register() {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [role, setRole] = useState('CONSUMER');
  const [error, setError] = useState('');
  const navigate = useNavigate();

  const handleRegister = async (e) => {
    e.preventDefault();
    setError('');

    try {
      await apiClient.post('/api/register', { email, password, role });

      // PROFESSIONAL LOGIC: No more alerts! 
      // We navigate directly to the login page and pass a silent success message in the background.
      navigate('/login', {
        state: { successMessage: "Account created successfully! Please sign in." }
      });

    } catch (err) {
      setError(err.response?.data?.detail || "Failed to connect to the server.");
    }
  };

  const handleGoogleSuccess = async (credentialResponse) => {
    try {
      const response = await apiClient.post('/api/auth/google', {
        token: credentialResponse.credential,
        role: role // This grabs the role they selected from your dropdown!
      });

      localStorage.setItem('userRole', response.data.role);
      localStorage.setItem('userEmail', response.data.email);
      navigate('/dashboard');

    } catch (err) {
      setError("Google registration failed.");
    }
  };

  return (
    <div className="flex min-h-screen bg-gray-900">
      {/* Left Side - Branding (Hidden on small mobile screens, takes up 50% on desktop) */}
      <div className="hidden md:flex md:w-1/2 bg-blue-900 flex-col justify-center items-center p-12 relative overflow-hidden">
        <div className="absolute inset-0 bg-linear-to-br from-blue-900 to-gray-900 opacity-90"></div>
        <div className="relative z-10 text-center">
          <h1 className="text-5xl font-bold text-white mb-6">BuildMart</h1>
          <p className="text-xl text-blue-200 max-w-md">
            The intelligent supply chain platform connecting producers, logistics, and consumers.
          </p>
        </div>
      </div>

      {/* Right Side - Form */}
      <div className="w-full md:w-1/2 flex items-center justify-center p-8 sm:p-12">
        <div className="w-full max-w-md space-y-8">
          <div>
            <h2 className="text-3xl font-extrabold text-white">Create an Account</h2>
            <p className="mt-2 text-gray-400">Join the BuildMart ecosystem today.</p>
          </div>

          <form className="mt-8 space-y-6" onSubmit={handleRegister}>
            <div className="space-y-4">
              <div>
                <label className="text-sm font-medium text-gray-300">Email address</label>
                <input
                  type="email" required
                  className="mt-1 w-full rounded-md border border-gray-600 bg-gray-800 px-4 py-3 text-white focus:border-blue-500 focus:outline-none focus:ring-1 focus:ring-blue-500 transition-colors"
                  placeholder="you@example.com"
                  value={email} onChange={(e) => setEmail(e.target.value)}
                />
              </div>

              <div>
                <label className="text-sm font-medium text-gray-300">Password</label>
                <input
                  type="password" required minLength="6"
                  className="mt-1 w-full rounded-md border border-gray-600 bg-gray-800 px-4 py-3 text-white focus:border-blue-500 focus:outline-none focus:ring-1 focus:ring-blue-500 transition-colors"
                  placeholder="ΓÇóΓÇóΓÇóΓÇóΓÇóΓÇóΓÇóΓÇó"
                  value={password} onChange={(e) => setPassword(e.target.value)}
                />
              </div>

              <div>
                <label className="text-sm font-medium text-gray-300">Account Type</label>
                <select
                  className="mt-1 w-full rounded-md border border-gray-600 bg-gray-800 px-4 py-3 text-white focus:border-blue-500 focus:outline-none focus:ring-1 focus:ring-blue-500 transition-colors"
                  value={role} onChange={(e) => setRole(e.target.value)}
                >
                  <option value="CONSUMER">Consumer (Buyer)</option>
                  <option value="PRODUCER">Producer (Supplier)</option>
                  <option value="LOGISTICS">Logistics (Driver)</option>
                </select>
              </div>
            </div>

            {error && <div className="text-sm text-red-400 bg-red-900/30 p-3 rounded-md border border-red-800">{error}</div>}

            <button type="submit" className="w-full rounded-md bg-blue-600 py-3 font-medium text-white hover:bg-blue-700 transition-colors shadow-lg shadow-blue-900/50">
              Register Now
            </button>
            {/* --- GOOGLE REGISTRATION BUTTON --- */}
            <div className="mt-6">
              <div className="relative">
                <div className="absolute inset-0 flex items-center">
                  <div className="w-full border-t border-gray-600"></div>
                </div>
                <div className="relative flex justify-center text-sm">
                  <span className="bg-gray-800 px-2 text-gray-400">Or register with</span>
                </div>
              </div>

              <div className="mt-6 flex justify-center">
                <GoogleLogin
                  onSuccess={handleGoogleSuccess}
                  onError={() => setError("Google Registration was closed or failed.")}
                  theme="filled_black"
                  shape="rectangular"
                  text="signup_with" // This changes the Google logo text to say "Sign up with Google"
                />
              </div>
            </div>
            {/* ---------------------------------- */}
          </form>

          <p className="text-center text-sm text-gray-400">
            Already have an account? <Link to="/login" className="text-blue-400 hover:text-blue-300 hover:underline font-medium">Log in here</Link>
          </p>
        </div>
      </div>
    </div>
  );
}
